styling.css:
.card {
 font-family: google sans;
 font-size: 20px;
 text-align: center;
 color: black;
 background-color: white;
}

.card {
  margin: 0;
  padding: 0;
  background: #f6f2ea;
  color: #202124;
  font-family: Inter, "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, "Noto Sans SC", "Microsoft YaHei", sans-serif;
  text-align: left;
}
.card {
  margin: 0;
  padding: 0;
  background: #f6f2ea;
  color: #202124;
  font-family: Inter, "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, "Noto Sans SC", "Microsoft YaHei", sans-serif;
  text-align: left;
}
.tc-shell {
  --topic: #2563eb;
  --accent: #38bdf8;
  box-sizing: border-box;
  min-height: 100vh;
  display: grid;
  grid-template-rows: auto 1fr;
  gap: 18px;
  padding: clamp(18px, 2.2vw, 34px);
  color: #202124;
  background: linear-gradient(120deg, color-mix(in srgb, var(--topic), transparent 91%), transparent 32%), linear-gradient(240deg, color-mix(in srgb, var(--accent), transparent 90%), transparent 34%), #f6f2ea;
}
.tc-page-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  width: min(96vw, 1380px);
  justify-self: center;
}
.tc-topic-kicker {
  color: var(--topic);
  font-size: 13px;
  font-weight: 950;
  line-height: 1.2;
  text-transform: uppercase;
}
.tc-topic-name {
  margin-top: 4px;
  color: #202124;
  font-size: clamp(26px, 3vw, 42px);
  line-height: 1;
  font-weight: 950;
}
.tc-topic-subtle {
  color: #69645b;
  font-size: 14px;
  font-weight: 850;
  margin-top: 6px;
}
.tc-frame {
  width: min(96vw, 1380px);
  min-height: min(82vh, 740px);
  display: grid;
  gap: clamp(16px, 2vw, 28px);
  justify-self: center;
  align-self: stretch;
}
.tc-single { min-height: min(82vh, 740px); }
.tc-two { grid-template-columns: minmax(540px, 1.24fr) minmax(500px, 0.96fr); align-items: stretch; }
.tc-card {
  box-sizing: border-box;
  border: 1.5px solid color-mix(in srgb, var(--topic), #ffffff 34%);
  border-radius: 8px;
  background: #fffdf8;
  box-shadow: 0 24px 58px rgba(37, 31, 22, 0.13);
}
.tc-study-card {
  min-height: min(82vh, 740px);
  display: grid;
  grid-template-rows: auto 1fr auto;
  gap: 18px;
  padding: clamp(36px, 5vw, 78px);
}
.tc-card-kicker { color: var(--topic); font-size: 13px; line-height: 1.2; font-weight: 950; text-transform: uppercase; }
.tc-main {
  align-self: center;
  display: block;
  color: var(--topic);
  font-size: clamp(58px, 6.9vw, 104px);
  line-height: 1.08;
  font-weight: 900;
  letter-spacing: 0;
  overflow-wrap: anywhere;
}
.tc-main * { font-size: inherit !important; line-height: inherit !important; font-weight: inherit !important; color: inherit !important; }
.tc-answer-main { font-size: clamp(48px, 5.4vw, 82px); color: #202124; }
.tc-hint { color: #69645b; font-size: 13px; font-weight: 850; }
.tc-syn-panel {
  min-height: min(82vh, 740px);
  display: grid;
  grid-template-rows: auto auto 1fr;
  gap: 12px;
  padding: clamp(20px, 2.4vw, 32px);
  border: 1.5px solid color-mix(in srgb, var(--topic), #ffffff 34%);
  border-radius: 8px;
  background: rgba(255,255,255,0.9);
  box-shadow: 0 24px 58px rgba(37, 31, 22, 0.1);
}
.tc-panel-kicker { color: var(--topic); font-size: 13px; line-height: 1.2; font-weight: 950; text-transform: uppercase; }
.tc-syn-panel h2 { margin: 0; color: #111827; font-size: clamp(28px, 2.3vw, 38px); line-height: 1.08; font-weight: 950; }
.tc-answer-facts {
  display: grid;
  gap: 6px;
  margin: 0 0 4px;
  padding: 0 0 16px;
  border-bottom: 1px solid #e3dbce;
  color: #202124;
  font-size: clamp(17px, 1.25vw, 21px);
  line-height: 1.45;
}
.tc-answer-facts b { font-weight: 950; }
.tc-syn-list { display: grid; gap: 12px; align-content: start; overflow: visible; }
.tc-syn-item {
  display: grid;
  gap: 6px;
  padding: 14px 16px;
  border-radius: 8px;
  background: #fff;
  box-shadow: 0 10px 22px rgba(37, 31, 22, 0.08);
}
.tc-syn-head { display: flex; align-items: flex-start; justify-content: space-between; gap: 10px; }
.tc-syn-phrase { color: #111827; font-size: clamp(17px, 1.25vw, 21px); line-height: 1.25; font-weight: 950; }
.tc-stance { flex: 0 0 auto; padding: 4px 8px; border-radius: 999px; background: #e5e7eb; color: #374151; font-size: 10px; line-height: 1; font-weight: 950; text-transform: uppercase; }
.tc-syn-zh, .tc-syn-example { margin: 0; color: #514c45; font-size: clamp(15px, 1.05vw, 18px); line-height: 1.5; }
.tc-empty-panel { color: #69645b; font-size: 18px; line-height: 1.5; font-weight: 750; }
.nightMode .card, .nightMode .tc-shell { background: #181715; color: #f6f2ea; }
.nightMode .tc-card, .nightMode .tc-syn-panel { background: #22201d; color: #f6f2ea; border-color: color-mix(in srgb, var(--topic), #22201d 32%); }
.nightMode .tc-topic-name, .nightMode .tc-answer-main, .nightMode .tc-syn-panel h2, .nightMode .tc-answer-facts, .nightMode .tc-syn-phrase { color: #f6f2ea; }
.nightMode .tc-syn-item { background: #2b2925; }
.nightMode .tc-syn-zh, .nightMode .tc-syn-example, .nightMode .tc-topic-subtle { color: #c9c2b8; }
@media (max-width: 980px) {
  .tc-shell { padding: 12px; }
  .tc-page-top, .tc-frame { width: calc(100vw - 24px); }
  .tc-two { grid-template-columns: 1fr; }
  .tc-study-card { min-height: 42vh; padding: 22px; }
  .tc-syn-panel { min-height: auto; padding: 16px; }
  .tc-main { font-size: clamp(36px, 10vw, 62px); }
  .tc-answer-main { font-size: clamp(32px, 8vw, 54px); }
}
